func AuditInstalledEntry(entry InstalledEntry, fallback *Package) []ValidationIssue {
	var issues []ValidationIssue
	root := installedRootPath(entry)
	if root == "" {
		issues = append(issues, ValidationIssue{Message: fmt.Sprintf("installed entry %q has no recorded plugin root", entry.Name)})
		return issues
	}

	issues = append(issues, auditRecordedFiles(entry)...)

	manifest, manifestMissing, manifestIssues := loadPackageDefinitionForAudit(root, fallback)
	issues = append(issues, manifestIssues...)

	if manifestMissing {
		issues = append(issues, ValidationIssue{
			Path:    filepath.Join(root, "package.yaml"),
			Message: "missing package.yaml",
		})
	}

	if manifest == nil {
		manifest = &Package{}
	}

	issues = append(issues, ValidatePackageStructure(root, manifest)...)
	return issues
}

// ValidatePackageStructure checks the skill, symlink, and executable layout
// for a package root before install or after install-state recovery.
func ValidatePackageStructure(root string, pkg *Package) []ValidationIssue {
	if pkg == nil {
		return []ValidationIssue{{Path: filepath.Join(root, "package.yaml"), Message: "missing package definition"}}
	}
	return auditPluginRoot(root, pkg)
}

func loadPackageDefinitionForAudit(root string, fallback *Package) (*Package, bool, []ValidationIssue) {
	manifest, manifestMissing, issues, err := LoadPackageManifestWithFallback(root, fallback)
	if err == nil || os.IsNotExist(err) {
		// Report validation issues even when package is valid, so audit shows schema problems.
		return manifest, manifestMissing, issues
	}

	// If a partial package was returned (YAML parsed but validation issues exist),
	// return it with the issues so structural audits can proceed.
	if manifest != nil {
		return manifest, false, issues
	}

	if len(issues) == 0 {
		issues = append(issues, ValidationIssue{Path: filepath.Join(root, "package.yaml"), Message: err.Error()})
	}
	return manifest, false, issues
}

func auditPluginRoot(root string, pkg *Package) []ValidationIssue {
	var issues []ValidationIssue

	if pkg.APIVersion != "" && pkg.APIVersion != SupportedPackageAPIVersion {
		issues = append(issues, ValidationIssue{
			Path:    filepath.Join(root, "package.yaml"),
			Message: fmt.Sprintf("unsupported `api_version` %q (supported: %s)", pkg.APIVersion, SupportedPackageAPIVersion),
		})
	}

	ignoredBrokenSymlinkPaths := collectIgnoredBrokenSymlinkPaths(root, pkg)
	for _, symlinkIssue := range auditBrokenSymlinks(root, ignoredBrokenSymlinkPaths) {
		issues = append(issues, symlinkIssue)
	}

	for _, skillRoot := range collectSkillRoots(root, pkg) {
		issues = append(issues, auditSkillRoot(root, skillRoot)...)
	}

	for _, rel := range pkg.Install.Executable {
		issues = append(issues, auditExecutable(root, rel)...)
	}

	return issues
}

func auditRecordedFiles(entry InstalledEntry) []ValidationIssue {
	var issues []ValidationIssue
	seen := map[string]bool{}
	recordedPaths := append([]string(nil), entry.Files...)
	if root := installedRootPath(entry); root != "" {
		recordedPaths = append(recordedPaths, root)
	}
	for _, recorded := range recordedPaths {
		path := ExpandHome(recorded)
		if path == "" || seen[path] {
			continue
		}
		seen[path] = true
		info, err := os.Lstat(path)
		if err != nil {
			if os.IsNotExist(err) {
				// Pre-migration entries whose paths begin with ~ are outside the
				// project root; treat missing paths as no-op (no issue raised).
				if strings.HasPrefix(recorded, "~") {
					continue
				}
				issues = append(issues, ValidationIssue{Path: path, Message: "missing recorded file or symlink"})
				continue
			}
			issues = append(issues, ValidationIssue{Path: path, Message: err.Error()})
			continue
		}
		if info.Mode()&os.ModeSymlink == 0 {
			continue
		}

		target, err := os.Readlink(path)
		if err != nil {
			issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("broken symlink: %v", err)})
			continue
		}
		if !filepath.IsAbs(target) {
			target = filepath.Join(filepath.Dir(path), target)
		}
		if _, err := os.Stat(target); err != nil {
			issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("broken symlink target %q: %v", target, err)})
		}
	}
	return issues
}

func auditBrokenSymlinks(root string, ignored map[string]bool) []ValidationIssue {
	var issues []ValidationIssue
	walkRoot := root
	if resolved, err := filepath.EvalSymlinks(root); err == nil && resolved != "" {
		walkRoot = resolved
	}

	_ = filepath.WalkDir(walkRoot, func(path string, d fs.DirEntry, err error) error {
		if err != nil {
			issues = append(issues, ValidationIssue{Path: path, Message: err.Error()})
			return nil
		}
		if path == walkRoot {
			return nil
		}

		info, err := os.Lstat(path)
		if err != nil {
			if os.IsNotExist(err) {
				issues = append(issues, ValidationIssue{Path: path, Message: "missing installed file"})
				return nil
			}
			issues = append(issues, ValidationIssue{Path: path, Message: err.Error()})
			return nil
		}
		if info.Mode()&os.ModeSymlink == 0 {
			return nil
		}
		if ignored != nil && ignored[path] {
			return nil
		}

		target, err := os.Readlink(path)
		if err != nil {
			issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("broken symlink: %v", err)})
			return nil
		}
		if !filepath.IsAbs(target) {
			target = filepath.Join(filepath.Dir(path), target)
		}
		if _, err := os.Stat(target); err != nil {
			issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("broken symlink target %q: %v", target, err)})
		}
		return nil
	})

	return issues
}

func collectSkillRoots(root string, pkg *Package) []string {
	seen := map[string]bool{}
	var roots []string

	add := func(candidate string) {
		if strings.TrimSpace(candidate) == "" {
			return
		}
		abs := candidate
		if resolved, err := filepath.EvalSymlinks(candidate); err == nil && resolved != "" {
			abs = resolved
		} else if resolved, err := filepath.Abs(candidate); err == nil && resolved != "" {
			abs = resolved
		}
		if seen[abs] {
			return
		}
		if _, err := os.Stat(candidate); err != nil {
			return
		}
		seen[abs] = true
		roots = append(roots, candidate)
	}

	for _, mapping := range pkg.Install.Skills {
		sourceRoot := filepath.Join(root, filepath.FromSlash(mapping.Source))
		add(sourceRoot)

		cleanSource := filepath.Clean(filepath.FromSlash(mapping.Source))
		switch cleanSource {

		switch cleanSource {
		case filepath.Join(".agents", "skills"), filepath.Join(".claude", "skills"):
			add(filepath.Join(root, "skills"))
		}
	}

	return roots
}

func collectIgnoredBrokenSymlinkPaths(root string, pkg *Package) map[string]bool {
	ignored := make(map[string]bool)
	for _, mapping := range pkg.Install.Skills {
		cleanSource := filepath.Clean(filepath.FromSlash(mapping.Source))
		switch cleanSource {
		case filepath.Join(".agents", "skills"), filepath.Join(".claude", "skills"):
			skillRoot := filepath.Join(root, cleanSource)
			entries, err := os.ReadDir(skillRoot)
			if err != nil {
				continue
			}
			for _, entry := range entries {
				ignored[filepath.Join(skillRoot, entry.Name())] = true
			}
		}
	}
	return ignored
}

func auditSkillRoot(packageRoot, root string) []ValidationIssue {
	var issues []ValidationIssue

	info, err := os.Stat(root)
	if err != nil {
		issues = append(issues, ValidationIssue{Path: root, Message: err.Error()})
		return issues
	}
	if !info.IsDir() {
		issues = append(issues, ValidationIssue{Path: root, Message: "expected a skill directory"})
		return issues
	}

	entries, err := os.ReadDir(root)
	if err != nil {
		issues = append(issues, ValidationIssue{Path: root, Message: err.Error()})
		return issues
	}

	for _, entry := range entries {
		skillPath := filepath.Join(root, entry.Name())
		skillInfo, err := os.Lstat(skillPath)
		if err != nil {
			issues = append(issues, ValidationIssue{Path: skillPath, Message: err.Error()})
			continue
		}
		if skillInfo.Mode()&os.ModeSymlink != 0 {
			if _, err := os.Stat(skillPath); err != nil {
				if recovered := recoverSkillDir(packageRoot, root, entry.Name()); recovered != "" {
					skillPath = recovered
				} else {
					issues = append(issues, ValidationIssue{Path: skillPath, Message: fmt.Sprintf("broken symlink: %v", err)})
					continue
				}
			}
		}
		if !skillInfo.IsDir() && skillInfo.Mode()&os.ModeSymlink == 0 {
			continue
		}

		skillFile := filepath.Join(skillPath, "SKILL.md")
		data, err := os.ReadFile(skillFile)
		if err != nil {
			if os.IsNotExist(err) {
				issues = append(issues, ValidationIssue{Path: skillPath, Message: "missing SKILL.md"})
				continue
			}
			issues = append(issues, ValidationIssue{Path: skillFile, Message: err.Error()})
			continue
		}

		for _, issue := range skills.ValidateContent(skillFile, data) {
			issues = append(issues, ValidationIssue{Path: issue.Path, Message: issue.Message})
		}
	}

	return issues
}

func recoverSkillDir(packageRoot, skillRoot, skillName string) string {
	candidate := filepath.Join(packageRoot, "skills", skillName)
	if info, err := os.Stat(candidate); err == nil && info.IsDir() {
		return candidate
	}

	if strings.HasSuffix(filepath.Clean(skillRoot), filepath.Join(".agents", "skills")) ||
		strings.HasSuffix(filepath.Clean(skillRoot), filepath.Join(".claude", "skills")) {
		candidate = filepath.Join(packageRoot, "skills", skillName)
		if info, err := os.Stat(candidate); err == nil && info.IsDir() {
			return candidate
		}
	}

	return ""
}

func auditExecutable(root, rel string) []ValidationIssue {
	path := filepath.Join(root, filepath.FromSlash(rel))
	info, err := os.Stat(path)
	if err != nil {
		return []ValidationIssue{{Path: path, Message: err.Error()}}
	}
	if info.IsDir() {
		return []ValidationIssue{{Path: path, Message: "expected executable file, found directory"}}
	}
	if info.Mode()&0111 == 0 {
		return []ValidationIssue{{Path: path, Message: "file lost execute permission"}}
	}
	return nil
}

func installedRootPath(entry InstalledEntry) string {
	resolve := func(raw string) string {
		expanded := ExpandHome(raw)
		// Pre-migration entries with ~/... paths are outside the project root.
		// Return empty string so callers skip audit for missing home paths.
		if strings.HasPrefix(raw, "~") {
			if _, err := os.Stat(expanded); err != nil {
				return ""
			}
		}
		return expanded
	}
	if len(entry.Files) > 0 {
		return resolve(entry.Files[0])
	}
	if strings.TrimSpace(entry.Source) != "" {
		return resolve(entry.Source)
	}
	return ""
}

package registry

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"gopkg.in/yaml.v3"
)

const SupportedPackageAPIVersion = "1"

// ValidationIssue represents one package or plugin validation problem.
type ValidationIssue struct {
	Path    string
	Message string
}

func (i ValidationIssue) Error() string {
	if i.Path == "" {
		return i.Message
	}
	return fmt.Sprintf("%s: %s", i.Path, i.Message)
}

type packageManifestRaw struct {
	Name        string         `yaml:"name"`
	Version     string         `yaml:"version"`
	Description string         `yaml:"description"`
	Type        string         `yaml:"type"`
	Source      string         `yaml:"source"`
	APIVersion  any            `yaml:"api_version"`
	Install     PackageInstall `yaml:"install"`
	Keywords    []string       `yaml:"keywords"`
}

// knownManifestKeys is the set of top-level keys consumed by the current
// manifest schema. Any additional keys are preserved on Package.Extra so
// manifests written against newer api_versions round-trip without silent
// field loss.
var knownManifestKeys = map[string]struct{}{
	"name":        {},
	"version":     {},
	"description": {},
	"type":        {},
	"source":      {},
	"api_version": {},
	"install":     {},
	"keywords":    {},
}

// LoadPackageManifest reads and validates package.yaml from root.
func LoadPackageManifest(root string) (*Package, []ValidationIssue, error) {
	manifestPath := filepath.Join(root, "package.yaml")
	data, err := os.ReadFile(manifestPath)
	if err != nil {
		return nil, nil, err
	}

	var raw packageManifestRaw
	if err := yaml.Unmarshal(data, &raw); err != nil {
		issue := ValidationIssue{
			Path:    manifestPath,
			Message: fmt.Sprintf("invalid YAML: %v", err),
		}
		return nil, []ValidationIssue{issue}, fmt.Errorf("%s: invalid YAML: %w", manifestPath, err)
	}

	// Also unmarshal into a free-form map so any keys not in the typed
	// struct survive as Package.Extra. yaml.v3 returns
	// map[string]any, preserving nested structure for round-trip.
	var full map[string]any
	if err := yaml.Unmarshal(data, &full); err != nil {
		// If the typed unmarshal succeeded, this cannot realistically
		// fail — but guard anyway.
		issue := ValidationIssue{
			Path:    manifestPath,
			Message: fmt.Sprintf("invalid YAML: %v", err),
		}
		return nil, []ValidationIssue{issue}, fmt.Errorf("%s: invalid YAML: %w", manifestPath, err)
	}

	pkg, issues := validatePackageManifest(manifestPath, raw)
	if pkg != nil {
		if extra := extraManifestKeys(full); len(extra) > 0 {
			pkg.Extra = extra
		}
	}
	if len(issues) > 0 && pkg == nil {
		return nil, issues, fmt.Errorf("%s: %s", manifestPath, JoinValidationIssues(issues))
	}
	// Even when validation issues exist, return the partial package so callers
	// can perform structural audits (symlinks, SKILL.md files) independently.
	// However, if no package was returned at all, return an error so callers
	// know something is fundamentally wrong.
	if pkg == nil {
		return nil, issues, fmt.Errorf("%s: %s", manifestPath, JoinValidationIssues(issues))
	}
	return pkg, issues, nil
}

// extraManifestKeys returns manifest keys that are not part of the current
// typed schema. Values are preserved as-is so callers can inspect them later.
func extraManifestKeys(full map[string]any) map[string]any {
	if len(full) == 0 {
		return nil
	}
	var extra map[string]any
	for k, v := range full {
		if _, known := knownManifestKeys[k]; known {
			continue
		}
		if extra == nil {
			extra = make(map[string]any, len(full))
		}
		extra[k] = v
	}
	return extra
}

// LoadPackageManifestWithFallback reads package.yaml and falls back to the
// provided package when the manifest is missing.
func LoadPackageManifestWithFallback(root string, fallback *Package) (*Package, bool, []ValidationIssue, error) {
	pkg, issues, err := LoadPackageManifest(root)
	if err == nil {
		// Return issues separately even when package is valid, so callers can
		// detect schema problems while still using the package for structural audits.
		if len(issues) > 0 {
			return pkg, false, issues, nil
		}
		return pkg, false, nil, nil
	}

	// If a partial package was returned (YAML parsed but validation issues exist),
	// return it with the issues so callers can still use its structure.
	if pkg != nil {
		return pkg, false, issues, nil
	}

	if os.IsNotExist(err) {
		return fallback, true, nil, err
	}

	if fallback != nil {
		return fallback, false, issues, err
	}
	return nil, false, issues, err
}

// validatePackageManifest validates required fields and returns a partial package
// even when validation issues are found. This ensures that structural audits
// (symlinks, SKILL.md files) can proceed independently of manifest schema issues.
func validatePackageManifest(path string, raw packageManifestRaw) (*Package, []ValidationIssue) {
	var issues []ValidationIssue

	name := strings.TrimSpace(raw.Name)
	if name == "" {
		issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `name`"})
	}
	version := strings.TrimSpace(raw.Version)
	if version == "" {
		issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `version`"})
	}
	description := strings.TrimSpace(raw.Description)
	if description == "" {
		issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `description`"})
	}
	pkgType, ok := parseManifestPackageType(raw.Type)
	if !ok {
		issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("unsupported `type` %q", strings.TrimSpace(raw.Type))})
	}
	source := strings.TrimSpace(raw.Source)
	if source == "" {
		issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `source`"})
	}

	apiVersion, apiIssue := parseAPIVersion(raw.APIVersion)
	if apiIssue != "" {
		issues = append(issues, ValidationIssue{Path: path, Message: apiIssue})
	}

	// Always construct a partial package so structural audits can proceed.
	// Validation issues are still collected and returned separately.
	pkg := &Package{
		Name:        name,
		Version:     version,
		Description: description,
		Type:        pkgType,
		Source:      source,
		APIVersion:  apiVersion,
		Install:     raw.Install,
		Keywords:    append([]string(nil), raw.Keywords...),
	}
	return pkg, issues
}

func parseManifestPackageType(rawType string) (PackageType, bool) {
	switch PackageType(strings.TrimSpace(rawType)) {
	case PackageTypeWorkflow, PackageTypePlugin, PackageTypePersonaPack, PackageTypeTemplatePack:
		return PackageType(strings.TrimSpace(rawType)), true
	default:
		return "", false
	}
}

func parseAPIVersion(raw any) (string, string) {
	if raw == nil {
		return "", "missing required field `api_version`"
	}

	value := strings.TrimSpace(fmt.Sprint(raw))
	if value == "" {
		return "", "missing required field `api_version`"
	}
	if value != SupportedPackageAPIVersion {
		return value, fmt.Sprintf("unsupported `api_version` %q (supported: %s)", value, SupportedPackageAPIVersion)
	}
	return value, ""
}

package registry

import (
	"archive/tar"
	"bytes"
	"compress/gzip"
	"fmt"
	"io"
	"net/http"
	"net/http/httptest"
	"os"
	"path/filepath"
	"strings"
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

func TestInstallPackageHonorsSkillSource(t *testing.T) {
	projectRoot := t.TempDir()
	server := newPackageArchiveServer(t, samplePackageTarball(t))
	defer server.Close()

	pkg := sampleInstallPackage(server.URL)
	entry, err := InstallPackage(pkg, projectRoot)
	require.NoError(t, err)

	for _, rel := range []string{
		filepath.Join(".agents", "skills", "ddx", "SKILL.md"),
		filepath.Join(".claude", "skills", "ddx", "SKILL.md"),
	} {
		path := filepath.Join(projectRoot, rel)
		data, readErr := os.ReadFile(path)
		require.NoError(t, readErr)
		assert.Contains(t, string(data), "ddx")
	}

	for _, rel := range []string{
		filepath.Join(".agents", "skills", "ddx", "SKILL.md"),
		filepath.Join(".claude", "skills", "ddx", "SKILL.md"),
	} {
		assert.Contains(t, entry.Files, rel)
	}
}

func TestInstallPackagePreservesUnrelatedProjectSkills(t *testing.T) {
	projectRoot := t.TempDir()
	server := newPackageArchiveServer(t, samplePackageTarball(t))
	defer server.Close()

	for _, rel := range []string{
		filepath.Join(".agents", "skills", "existing-skill", "SKILL.md"),
		filepath.Join(".claude", "skills", "existing-skill", "SKILL.md"),
	} {
		path := filepath.Join(projectRoot, rel)
		require.NoError(t, os.MkdirAll(filepath.Dir(path), 0o755))
		require.NoError(t, os.WriteFile(path, []byte("keep me"), 0o644))
	}

	_, err := InstallPackage(sampleInstallPackage(server.URL), projectRoot)
	require.NoError(t, err)

	for _, rel := range []string{
		filepath.Join(".agents", "skills", "existing-skill", "SKILL.md"),
		filepath.Join(".claude", "skills", "existing-skill", "SKILL.md"),
	} {
		path := filepath.Join(projectRoot, rel)
		data, readErr := os.ReadFile(path)
		require.NoError(t, readErr)
		assert.Equal(t, "keep me", string(data))
	}
}

func TestInstallPackageRecordsManifestSkillTargets(t *testing.T) {
	projectRoot := t.TempDir()
	server := newPackageArchiveServer(t, samplePackageTarball(t))
	defer server.Close()

	entry, err := InstallPackage(sampleInstallPackage(server.URL), projectRoot)
	require.NoError(t, err)

	for _, rel := range []string{
		filepath.Join(".agents", "skills", "ddx", "SKILL.md"),
		filepath.Join(".claude", "skills", "ddx", "SKILL.md"),
	} {
		assert.Contains(t, entry.Files, rel)
	}
}

func sampleInstallPackage(source string) *Package {
	return &Package{
		Name:    "sample-plugin",
		Version: "1.0.0",
		Type:    PackageTypePlugin,
		Source:  source,
		Install: PackageInstall{
			Root: &InstallMapping{
				Source: ".",
				Target: ".ddx/plugins/sample-plugin",
			},
			Skills: []InstallMapping{
				{Source: "skills/", Target: ".agents/skills/"},
				{Source: "skills/", Target: ".claude/skills/"},
			},
		},
	}
}

func samplePackageTarball(t *testing.T) []byte {
	t.Helper()

	var buf bytes.Buffer
	gz := gzip.NewWriter(&buf)
	tw := tar.NewWriter(gz)

	topDir := "sample-plugin-1.0.0"
	writeTarDir(t, tw, topDir)
	writeTarFile(t, tw, filepath.Join(topDir, "package.yaml"), []byte(fmt.Sprintf(`name: sample-plugin
version: 1.0.0
description: Sample package
type: plugin
source: https://example.com/sample-plugin
api_version: 1
install:
  root:
    source: .
    target: .ddx/plugins/sample-plugin
  skills:
    - source: skills/
      target: .agents/skills/
    - source: skills/
      target: .claude/skills/
`, topDir)))
	writeTarDir(t, tw, filepath.Join(topDir, "skills"))
	writeTarDir(t, tw, filepath.Join(topDir, "skills", "ddx"))
	writeTarFile(t, tw, filepath.Join(topDir, "skills", "ddx", "SKILL.md"), []byte("---\nname: ddx\ndescription: sample\n---\n# ddx\n"))

	require.NoError(t, tw.Close())
	require.NoError(t, gz.Close())
	return buf.Bytes()
}

func newPackageArchiveServer(t *testing.T, payload []byte) *httptest.Server {
	t.Helper()

	return httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		if !strings.HasSuffix(r.URL.Path, "/archive/refs/tags/v1.0.0.tar.gz") {
			t.Errorf("unexpected archive path: %s", r.URL.Path)
		}
		w.Header().Set("Content-Type", "application/gzip")
		_, _ = w.Write(payload)
	}))
}

func writeTarDir(t *testing.T, tw *tar.Writer, name string) {
	t.Helper()

	require.NoError(t, tw.WriteHeader(&tar.Header{
		Name:     filepath.ToSlash(name) + "/",
		Mode:     0o755,
		Typeflag: tar.TypeDir,
	}))
}

func writeTarFile(t *testing.T, tw *tar.Writer, name string, body []byte) {
	t.Helper()

	require.NoError(t, tw.WriteHeader(&tar.Header{
		Name:     filepath.ToSlash(name),
		Mode:     0o644,
		Size:     int64(len(body)),
		Typeflag: tar.TypeReg,
	}))
	_, err := tw.Write(body)
	require.NoError(t, err)
}

package registry

import (
	"archive/tar"
